#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 50005

int R, C;
char maze[MAX][MAX];
int visited[MAX][MAX];
int directions[][2] = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

int is_valid(int x, int y) {
    return x >= 0 && x < R && y >= 0 && y < C && maze[x][y] == 'o' && !visited[x][y];
}

void bfs(int x, int y) {
    visited[x][y] = 1;
    for (int i = 0; i < 4; i++) {
        int nx = x + directions[i][0];
        int ny = y + directions[i][1];
        if (is_valid(nx, ny)) {
            bfs(nx, ny);
        }
    }
}

int count_reachable_cells(int x, int y) {
    memset(visited, 0, sizeof(visited));
    bfs(x, y);
    int count = 0;
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            if (visited[i][j]) {
                count++;
            }
        }
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &R, &C);
        for (int i = 0; i < R; i++) {
            scanf("%s", maze[i]);
        }
        int start_reachable = count_reachable_cells(0, 0);
        int goal_reachable = count_reachable_cells(R-1, C-1);
        double probability = (double)goal_reachable / start_reachable;
        double expected_clicks = 1 / probability;
        printf("%.6f\n", expected_clicks);
    }
    return 0;
}

