import java.util.Scanner;
public class Main {
    static final int MAX = 50005;
    static int R, C;
    static char[][] maze = new char[MAX][MAX];
    static boolean[][] visited = new boolean[MAX][MAX];
    static int[][] directions = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

    public static boolean is_valid(int x, int y) {
        return x >= 0 && x < R && y >= 0 && y < C && maze[x][y] == 'o' && !visited[x][y];
    }

    public static void bfs(int x, int y) {
        visited[x][y] = true;
        for (int i = 0; i < 4; i++) {
            int nx = x + directions[i][0];
            int ny = y + directions[i][1];
            if (is_valid(nx, ny)) {
                bfs(nx, ny);
            }
        }
    }

    public static int count_reachable_cells(int x, int y) {
        for (boolean[] row : visited) {
            for (int i = 0; i < row.length; i++) {
                row[i] = false;
            }
        }
        bfs(x, y);
        int count = 0;
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                if (visited[i][j]) {
                    count++;
                }
            }
        }
        return count;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            R = scanner.nextInt();
            C = scanner.nextInt();
            for (int i = 0; i < R; i++) {
                String row = scanner.next();
                maze[i] = row.toCharArray();
            }
            int start_reachable = count_reachable_cells(0, 0);
            int goal_reachable = count_reachable_cells(R-1, C-1);
            double probability = (double)goal_reachable / start_reachable;
            double expected_clicks = 1 / probability;
            System.out.printf("%.6f\n", expected_clicks);
        }
    }
}

