const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];

const MAX = 50005;
const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

function is_valid(x, y, R, C, maze, visited) {
    return x >= 0 && x < R && y >= 0 && y < C && maze[x][y] === 'o' && !visited[x][y];
}

function bfs(x, y, R, C, maze, visited) {
    visited[x][y] = true;
    for (const [dx, dy] of directions) {
        const nx = x + dx;
        const ny = y + dy;
        if (is_valid(nx, ny, R, C, maze, visited)) {
            bfs(nx, ny, R, C, maze, visited);
        }
    }
}

function count_reachable_cells(x, y, R, C, maze) {
    const visited = Array(R).fill(0).map(() => Array(C).fill(false));
    bfs(x, y, R, C, maze, visited);
    return visited.reduce((acc, row) => acc + row.filter(Boolean).length, 0);
}

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [R, C] = readline().split(' ').map(Number);
    const maze = Array(R).fill(0).map(() => readline().trim().split(''));
    const start_reachable = count_reachable_cells(0, 0, R, C, maze);
    const goal_reachable = count_reachable_cells(R-1, C-1, R, C, maze);
    const probability = goal_reachable / start_reachable;
    const expected_clicks = 1 / probability;
    console.log(expected_clicks.toFixed(6));
}
